/**
 * Applies mocks in one shot (single header update). Prefer this over
 * {@link MockClient.reset}, which rebuilds headers twice and can briefly clear
 * `x-mock-request`, breaking MSW and the running page.
 */
async function applyServerMocks(
  page: Page,
  configure: (client: MockClient) => Promise<void>,
) {
  const client = new MockClient();
  client.onChange = async (headers) => page.context().setExtraHTTPHeaders(headers);
  await configure(client);
}

/**
 * TanStack Start + Vite dev can expose HTML before the client bundle has attached
 * React's input listeners; typing too early updates the DOM but not React state.
 * Preview/CI is usually fine with {@link Page.goto}'s `networkidle` alone.
 */
async function gotoWorkspaceNew(page: Page) {
  await page.goto("/workspace/new", { waitUntil: "networkidle" });
  if (!process.env.CI) {
    await page.waitForTimeout(3000);
  }
}

