/**
 * Builds a path + query string for org API scoped resources (e.g. campaigns).
 * OpenAPI uses `tenant_id` and optional `vendor_id` as query parameters.
 */
export function orgApiScopedPath(
  pathname: string,
  scope: { tenantId: number; vendorId?: number },
): string {
  const normalized = pathname.startsWith("/") ? pathname : `/${pathname}`;
  const params = new URLSearchParams();
  params.set("tenant_id", String(scope.tenantId));
  if (scope.vendorId !== undefined) {
    params.set("vendor_id", String(scope.vendorId));
  }
  const query = params.toString();
  return `${normalized}?${query}`;
}

