import type { Tenant } from "@/types/bootstrap";

/**
 * Maps the current workspace tenant to org API query scope (`tenant_id`, optional `vendor_id`).
 * For vendor workspaces, sends `vendor_id` when we can derive a numeric id from `vendor_id` or fall back to tenant id.
 */
export function campaignApiScopeFromTenant(tenant: Tenant): {
  tenantId: number;
  vendorId?: number;
} {
  const tenantId = tenant.id;
  if (tenant.tenant_type !== "vendor") {
    return { tenantId };
  }
  const parsed = firstIntegerFromString(tenant.vendor_id);
  return {
    tenantId,
    vendorId: parsed ?? tenantId,
  };
}

function firstIntegerFromString(value: string | null): number | undefined {
  if (!value) {
    return undefined;
  }
  const match = value.match(/(\d+)/);
  if (!match) {
    return undefined;
  }
  return Number.parseInt(match[1], 10);
}

