import { getAppBootstrapData } from "./app-bootstrap";
import { listCampaigns } from "./campaigns";
import { OrgApiError } from "./error";

export type DashboardCampaign = {
  id: number;
  name: string;
};

export type DashboardPageData = {
  campaigns: DashboardCampaign[];
  cards: {
    campaigns: number;
    payouts: number;
    transactions: number;
  };
};

export async function getDashboardPageData(): Promise<DashboardPageData | null> {
  const bootstrap = await getAppBootstrapData();
  if (!bootstrap?.currentTenant) {
    return null;
  }

  try {
    const campaigns = (await listCampaigns()) ?? [];
    const simplified = campaigns.map((c) => ({ id: c.id, name: c.name }));

    return {
      campaigns: simplified,
      cards: {
        campaigns: simplified.length,
        payouts: 7,
        transactions: 428,
      },
    };
  } catch (error) {
    if (error instanceof OrgApiError && error.status === 401) {
      throw error;
    }
    throw error;
  }
}

import { useState } from "react";
import {
  createFileRoute,
  redirect,
  useNavigate,
  useRouter,
} from "@tanstack/react-router";
import { Button, Card, Input } from "@workspace/ui";
import { Loader2, X } from "lucide-react";
import { Field, FieldLabel } from "../../../components/ui/field";
import { getAppBootstrapData } from "../../../server/app-bootstrap";
import { createCampaignFn } from "../../../server/campaigns.functions";

export const Route = createFileRoute("/_authed/campaigns/new")({
  loader: async () => {
    const bootstrap = await getAppBootstrapData();
    if (bootstrap?.currentTenant?.tenant_type === "vendor") {
      throw redirect({ to: "/" });
    }
    return null;
  },
  component: CampaignCreatePage,
});

function CampaignCreatePage() {
  const navigate = useNavigate();
  const router = useRouter();
  const [name, setName] = useState("");
  const [isCreating, setIsCreating] = useState(false);

  const canCreate = name.trim().length > 0;

  const handleCreate = async () => {
    if (!canCreate) return;

    const trimmedName = name.trim();

    setIsCreating(true);
    try {
      const campaign = await createCampaignFn({
        data: { name: trimmedName },
      });

      await router.invalidate();

      navigate({
        to: "/campaigns/$campaignId",
        params: { campaignId: campaign.id.toString() },
      });
    } finally {
      setIsCreating(false);
    }
  };

  const handleClose = () => {
    navigate({ to: "/" });
  };

  return (
    <div className="flex min-h-screen items-center justify-center bg-foreground/40 p-6 font-outfit backdrop-blur-sm">
      <Card className="w-full max-w-md overflow-hidden shadow-2xl">
        <div className="flex items-center justify-between p-6 pb-0">
          <h2 className="font-bold text-foreground text-lg">Create campaign</h2>
          <Button
            type="button"
            onClick={handleClose}
            variant="ghost"
            size="icon-sm"
            aria-label="Close create campaign"
            className="text-muted-foreground hover:text-foreground"
          >
            <X size={16} />
          </Button>
        </div>

        <div className="flex flex-col gap-5 p-6">
          <Field>
            <FieldLabel htmlFor="name">Campaign name</FieldLabel>
            <Input
              id="name"
              value={name}
              onChange={(e) => setName(e.target.value)}
              placeholder="e.g. Spring Gala 2026"
              className="h-10"
            />
          </Field>
        </div>

        <div className="flex justify-end gap-2.5 border-border border-t p-4">
          <Button variant="outline" onClick={handleClose}>
            Cancel
          </Button>
          <Button disabled={!canCreate || isCreating} onClick={handleCreate}>
            {isCreating && <Loader2 className="animate-spin" size={16} />}
            {isCreating ? "Creating..." : "Create campaign"}
          </Button>
        </div>
      </Card>
    </div>
  );
}

import { useState } from "react";
import {
  createFileRoute,
  Link,
  notFound,
  redirect,
} from "@tanstack/react-router";
import { createServerFn } from "@tanstack/react-start";
import { Button, Card, Heading, Input, Paragraph, Separator } from "@workspace/ui";
import { ArrowLeft, Loader2 } from "lucide-react";
import { z } from "zod";
import { AppHeader } from "../../../components/app-header";
import { Field, FieldLabel } from "../../../components/ui/field";
import { updateCampaignFn } from "../../../server/campaigns.functions";

const getCampaignDetailPageDataFn = createServerFn({ method: "GET" })
  .inputValidator(
    z.object({
      campaignId: z.string(),
    }),
  )
  .handler(async ({ data }) => {
    const { getCampaignDetailPageData } = await import(
      "../../../server/campaigns"
    );
    const { OrgApiError } = await import("../../../server/error");

    try {
      const pageData = await getCampaignDetailPageData(data.campaignId);

      if (!pageData.campaign) {
        throw notFound();
      }

      return pageData;
    } catch (error) {
      if (error instanceof OrgApiError && error.status === 401) {
        throw redirect({ to: "/login" });
      }

      throw error;
    }
  });

export const Route = createFileRoute("/_authed/campaigns/$campaignId")({
  loader: ({ params }) =>
    getCampaignDetailPageDataFn({ data: { campaignId: params.campaignId } }),
  component: CampaignDetailPage,
});

function formatDateTime(iso: string) {
  try {
    return new Date(iso).toLocaleString();
  } catch {
    return iso;
  }
}

function CampaignDetailPage() {
  const { campaignId } = Route.useParams();
  const { campaign } = Route.useLoaderData();
  const router = Route.useRouter();
  const [isEditing, setIsEditing] = useState(false);
  const [editedName, setEditedName] = useState(campaign.name);
  const [isSaving, setIsSaving] = useState(false);
  const [saveError, setSaveError] = useState<string | null>(null);

  const handleSave = async () => {
    const trimmed = editedName.trim();
    if (!trimmed) return;

    setSaveError(null);
    setIsSaving(true);
    try {
      await updateCampaignFn({
        data: { campaignId, name: trimmed },
      });
      await router.invalidate();
      setIsEditing(false);
    } catch {
      setSaveError("Could not save changes. Try again.");
    } finally {
      setIsSaving(false);
    }
  };

  const handleCancelEdit = () => {
    setEditedName(campaign.name);
    setSaveError(null);
    setIsEditing(false);
  };

  return (
    <div className="min-h-screen bg-muted font-outfit">
      <AppHeader />

      <main className="mx-auto max-w-2xl px-6 py-8">
        <Link
          to="/"
          className="mb-6 inline-flex items-center gap-1.5 font-medium text-muted-foreground text-sm transition-colors hover:text-foreground"
        >
          <ArrowLeft size={14} />
          Back to dashboard
        </Link>

        <Heading as="h1" className="mb-6 font-bold text-2xl text-foreground">
          {campaign.name}
        </Heading>

        <Card className="p-6">
          <Heading as="h2" className="mb-4 font-semibold text-foreground text-lg">
            Campaign details
          </Heading>
          <dl className="space-y-3 text-sm">
            <div>
              <dt className="font-medium text-muted-foreground">ID</dt>
              <dd className="mt-0.5 text-foreground">{campaign.id}</dd>
            </div>
            <div>
              <dt className="font-medium text-muted-foreground">Name</dt>
              <dd className="mt-0.5 text-foreground">{campaign.name}</dd>
            </div>
            <div>
              <dt className="font-medium text-muted-foreground">Created</dt>
              <dd className="mt-0.5 text-foreground">
                {formatDateTime(campaign.created_at)}
              </dd>
            </div>
            <div>
              <dt className="font-medium text-muted-foreground">Updated</dt>
              <dd className="mt-0.5 text-foreground">
                {formatDateTime(campaign.updated_at)}
              </dd>
            </div>
          </dl>

          <Separator className="my-6" />

