  const router = useRouter();
  const [isCreating, setIsCreating] = useState(false);
  const [formError, setFormError] = useState<string | null>(null);
  const [formKey, setFormKey] = useState(0);

  useEffect(() => {
    if (!open) {
      setFormError(null);
      setFormKey((k) => k + 1);
    }
  }, [open]);

  const submitCampaign = async (form: HTMLFormElement) => {
    const formData = new FormData(form);
    const rawName = formData.get("campaignName");
    const trimmedName = typeof rawName === "string" ? rawName.trim() : "";
    if (!trimmedName) {
      return;
    }

    setFormError(null);
    setIsCreating(true);
    try {
      const campaign = await createCampaignFn({
        data: { name: trimmedName },
      });

      await router.invalidate();
      onOpenChange(false);
      await navigate({
        to: "/campaigns/$campaignId",
        params: { campaignId: campaign.id.toString() },
      });
    } catch {
      setFormError("Could not create campaign. Please try again.");
    } finally {
      setIsCreating(false);
    }
  };

  const handleFormSubmit = (event: SubmitEvent<HTMLFormElement>) => {
    event.preventDefault();
    void submitCampaign(event.currentTarget);
  };

  return (
    <Dialog onOpenChange={onOpenChange} open={open}>
      <DialogContent className="font-outfit sm:max-w-md">
        <DialogHeader>
          <DialogTitle>Create campaign</DialogTitle>
        </DialogHeader>

        <form key={formKey} method="post" onSubmit={handleFormSubmit}>
          <div className="flex flex-col gap-4 py-2">
            <Field>
              <FieldLabel htmlFor="create-campaign-modal-name">
                Campaign name
              </FieldLabel>
              <Input
                autoComplete="off"
                className="h-10"
                id="create-campaign-modal-name"
                minLength={1}
                name="campaignName"
                placeholder="e.g. Spring Gala 2026"
                required
              />
            </Field>
            {formError ? (
              <p className="text-destructive text-sm" role="alert">
                {formError}
              </p>
            ) : null}
          </div>

          <DialogFooter className="gap-2 sm:gap-2">
            <Button
              type="button"
              variant="outline"
              onClick={() => onOpenChange(false)}
            >
              Cancel
            </Button>
            <Button disabled={isCreating} type="submit">
              {isCreating && <Loader2 className="animate-spin" size={16} />}
              {isCreating ? "Creating..." : "Create campaign"}
            </Button>
          </DialogFooter>
        </form>
      </DialogContent>
    </Dialog>
  );
}

