test("creates a campaign and navigates to its detail page without client errors", async ({
  page,
  mockServerRequest,
}) => {
  const pageErrors: string[] = [];
  const consoleErrors: string[] = [];

  page.on("pageerror", (error) => {
    pageErrors.push(error.message);
  });
  page.on("console", (message) => {
    if (message.type() === "error") {
      consoleErrors.push(message.text());
    }
  });

  await mockServerRequest.GET(usersApiPattern, { body: mockUser });
  await mockServerRequest.GET(tenantsApiPattern, { body: [mockOrgTenant] });

  await page.goto("/campaigns/new", { waitUntil: "networkidle" });

  await page.locator("#campaign-name").fill("Spring Drive");

  await mockServerRequest.reset();
  await mockServerRequest.GET(usersApiPattern, { body: mockUser });
  await mockServerRequest.GET(tenantsApiPattern, { body: [mockOrgTenant] });
  await mockServerRequest.POST(createCampaignPattern, { body: mockCampaign });
  await mockServerRequest.GET(campaignShowPattern, { body: mockCampaign });

  await page.getByRole("button", { name: "Create campaign" }).click();

  await expect(page).toHaveURL(/\/campaigns\/101$/);
  await expect(
    page.getByRole("heading", { name: "Spring Drive", exact: true }),
  ).toBeVisible();
  await expect(pageErrors).toEqual([]);
  expect(consoleErrors.some((message) => message.includes("removeChild"))).toBe(
    false,
  );
});

